    def _draw_vegvisir(self):
        if not PIL_OK:
            return
        try:
            self.update_idletasks()
            pw = self._bg_canvas.winfo_width() or 620
            ph = self._bg_canvas.winfo_height() or 920
            global _VEGVISIR_PIL_CACHE
            if _VEGVISIR_PIL_CACHE is None:
                raw = base64.b64decode(VEGVISIR_B64)
                buf = io.BytesIO(raw)
                buf.seek(0)
                _VEGVISIR_PIL_CACHE = Image.open(buf).convert("RGBA")
            img = _VEGVISIR_PIL_CACHE.copy()
            bg_col = tuple(int(COL_C.lstrip("#")[i:i+2], 16) for i in (0,2,4))
            bg = Image.new("RGBA", img.size, bg_col + (255,))
            r2, g2, b2, a2 = img.split()
            a2 = a2.point(lambda p: int(p * 0.90))
            img.putalpha(a2)
            bg.paste(img, mask=img.split()[3])
            size = 160
            bg = bg.resize((size, size), Image.LANCZOS)
            photo = ImageTk.PhotoImage(bg)
            self._veg_photo = photo
            self._bg_canvas.delete("vegvisir")
            self._bg_canvas.create_image(pw//2, 90, image=photo, anchor="center", tags="vegvisir")
            # Lower the image tag below the canvas window (inner frame)
            self._bg_canvas.tag_lower("vegvisir")
        except Exception as e:
            import traceback
            print("[WM] ERROR:", e)
            traceback.print_exc()


    def _save_ip(self):
        """Save the IP immediately without patching the miner."""
        global MINER_IP, API_URL
        new_ip = self._ip_entry.get().strip()
        if not new_ip:
            self._ip_status.config(text="  ⚠ IP cannot be empty", fg=ORANGE)
            return
        MINER_IP = new_ip
        API_URL  = "http://" + MINER_IP + "/api/system/info"
        self.miner_ip = new_ip
        save_config({"miner_ip": MINER_IP})
        self._ip_status.config(
            text=f"  ✔ Saved — connecting to {new_ip}", fg=GREEN)
        self.after(3000, lambda: self._ip_status.config(text="", fg=DIM))

    def _load_alert_fields(self):
        acfg=load_alert_config()
        for k in ("ntfy_topic","alert_temp_threshold","alert_vr_temp_threshold","alert_hash_threshold"):
            if k in self._fields:
                e=self._fields[k]
                e.delete(0, tk.END)
                e.insert(0,str(acfg.get(k,"")))  # FIX2: was "end" string, use tk.END constant
        for fk in ("alert_on_block","alert_on_offline"):
            v=getattr(self,f"_flag_{fk}",None)
            if v: v.set(bool(acfg.get(fk,True)))

    def _save_alert_fields(self):
        ALERT_KEYS={"ntfy_topic","alert_temp_threshold","alert_vr_temp_threshold","alert_hash_threshold"}
        acfg=load_alert_config()
        for k in ALERT_KEYS:
            if k in self._fields:
                raw=self._fields[k].get().strip()
                try:  # BUG#3 FIX (v3.9.5): guard against non-numeric input
                    acfg[k] = raw if k == "ntfy_topic" else float(raw or 0)
                except (ValueError, TypeError):
                    acfg[k] = raw if k == "ntfy_topic" else 0.0
        for fk in ("alert_on_block","alert_on_offline"):
            v=getattr(self,f"_flag_{fk}",None)
            if v: acfg[fk]=v.get()
        save_alert_config(acfg)
        return ALERT_KEYS

    def _test_ntfy(self):
        import tkinter.messagebox as _mb
        url = self._fields.get("ntfy_topic", type("", (), {"get": lambda s: ""})()).get().strip()
        if not url:
            _mb.showwarning("No Topic", "Enter an ntfy Topic URL first.", parent=self)
            return
        _url = url if url.startswith(("http://", "https://")) else "https://ntfy.sh/" + url.lstrip("/")
        safe_title = "RavenMiner HQ Test Alert"
        try:
            resp = requests.post(
                _url,
                data=f"ntfy working! Miner: {self.miner_ip}".encode("utf-8"),
                headers={
                    "Title":        safe_title,
                    "Priority":     "default",
                    "Tags":         "white_check_mark",
                    "Content-Type": "text/plain; charset=utf-8",
                },
                timeout=8,
            )
            if resp.status_code in (200, 201, 204):
                _mb.showinfo(
                    "Test Sent",
                    f"Notification delivered!\nHTTP {resp.status_code}\nURL: {_url}",
                    parent=self,
                )
            else:
                _mb.showerror(
                    "ntfy Error",
                    f"Server returned HTTP {resp.status_code}\n{resp.text[:300]}\n\nURL: {_url}",
                    parent=self,
                )
        except Exception as ex:
            _mb.showerror(
                "ntfy Connection Error",
                f"{ex}\n\nURL: {_url}\n\nCheck URL and internet access.",
                parent=self,
            )
    def _load(self):
        endpoints = [
            f"http://{self.miner_ip}/api/system/config",
            f"http://{self.miner_ip}/api/swarm/info",
            f"http://{self.miner_ip}/api/system/info",
        ]
        cfg = None
        last_err = None
        for url in endpoints:
            try:
                r = requests.get(url, timeout=5)
                if r.status_code == 200 and r.text.strip():
                    cfg = r.json()
                    break
            except Exception as ex:
                last_err = ex
        if cfg is None:
            # Silent fail on auto-load (no popup on startup)
            if last_err:
                print(f"Settings load warning: {last_err}")
            return
        # Map our field keys -> actual API response keys where different
        load_remap = {
            "pidTargetTemp":  "temptarget",
            "manualFanSpeed": "fanspeed",
        }
        for key, entry in self._fields.items():
            if key == "miner_ip":
                continue
            api_key = load_remap.get(key, key)
            val = cfg.get(api_key, "")
            entry.delete(0, tk.END)
            entry.insert(0, str(val) if val is not None else "")

    def _apply(self):
        import tkinter.messagebox as mb
        # Build payload with correct types
        int_keys    = {"coreVoltage", "frequency", "stratumPort", "fallbackStratumPort",
                       "pidTargetTemp", "overheat_temp", "manualFanSpeed", "stratumDifficulty"}
        bool_keys   = {"stratumTLS", "fallbackStratumTLS", "autofanspeed",
                       "flipscreen", "invertscreen", "autoscreenoff"}
        new_ip = self._fields["miner_ip"].get().strip() if "miner_ip" in self._fields else self.miner_ip

        data = {}
        excluded_keys=self._save_alert_fields()
        excluded_keys.add("miner_ip")
        for k, entry in self._fields.items():
            if k in excluded_keys:
                continue
            raw = entry.get().strip()
            if not raw:
                continue
            if k in int_keys:
                try: data[k] = int(raw)
                except ValueError: data[k] = raw
            elif k in bool_keys:
                data[k] = raw.lower() in ("1", "true", "yes", "on")
            else:
                data[k] = raw
        try:
            url  = f"http://{self.miner_ip}/api/system"
            resp = requests.patch(url, json=data, timeout=8)
            if resp.status_code in (200, 201, 204):
                if new_ip and new_ip != self.miner_ip:
                    global MINER_IP, API_URL
                    MINER_IP = new_ip
                    API_URL  = "http://" + MINER_IP + "/api/system/info"
                    self.miner_ip = new_ip
                save_config({"miner_ip": MINER_IP})
                mb.showinfo("Success", "Settings applied!\nMiner may restart.", parent=self)
                self.destroy()
            else:
                raise Exception(f"Miner returned HTTP {resp.status_code}:\n{resp.text[:300]}")
        except Exception as ex:
            mb.showerror("Apply Error", str(ex), parent=self)

    def _on_reboot_toggle(self):
        if self._reboot_var.get():
            self._reboot_toggle.config(text="ON ", fg=RED)
            self._reboot_slider_lbl.config(fg=ORANGE)
        else:
            self._reboot_toggle.config(text="OFF", fg=DIM)
            self._reboot_slider.set(0)
            self._reboot_slider_lbl.config(fg=DIM, text="  Slide to confirm → hold for 2s to reboot")

    def _on_reboot_slide(self, val):
        v = int(val)
        if v >= 100 and self._reboot_var.get():
            self._reboot_slider_lbl.config(
                text="  HOLD — rebooting...", fg=RED)
            if self._reboot_hold_id is None:
                self._reboot_hold_id = self.after(2000, self._do_reboot)
        else:
            if self._reboot_hold_id:
                self.after_cancel(self._reboot_hold_id)
                self._reboot_hold_id = None
            if self._reboot_var.get():
                pct = int(v)
                self._reboot_slider_lbl.config(
                    fg=ORANGE if pct > 50 else DIM,
                    text=f"  {'▶' * (pct // 10)}{'·' * (10 - pct // 10)}  {pct}%  — release to cancel")

    def _do_reboot(self):
        self._reboot_hold_id = None
        try:
            requests.post(f"http://{self.miner_ip}/api/system/restart", timeout=5)
            import tkinter.messagebox as mb
            mb.showinfo("Reboot", "Reboot command sent to miner.", parent=self)
            if getattr(self, "_dash", None) is not None:
                self._dash._reboot_pending = True  # v4.0.1 show LOST CONNECTION
            self.destroy()  # Close settings window after successful reboot
            return
        except Exception as ex:
            import tkinter.messagebox as mb
            mb.showerror("Reboot Error", str(ex), parent=self)
        self._reboot_slider.set(0)
        self._reboot_var.set(False)
        self._on_reboot_toggle()


