    root.withdraw()

    cfg = load_config()
    if "miner_ip" not in cfg:
        dlg = IPSetupDialog(root, DEFAULT_MINER_IP)
        root.wait_window(dlg)
        MINER_IP = dlg.result
        API_URL  = "http://" + MINER_IP + "/api/system/info"
        save_config({"miner_ip": MINER_IP})

    root.deiconify()
    RavenMinerDash(root)
    root.mainloop()